var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"왜 그러지? 벗을 구하고 싶다고 하지 않았나?","JPN":"どうした？　友を助けたいのではなかったのか？","ENG":"Why the hesitation? Did you not say you wanted to save your friend?","TWN":"怎麼了？不是說想救朋友嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큰소리친 것치고는 별 볼 일 없군.","JPN":"大口を叩いた割には、大したことないな。","ENG":"For all that bravado, you are rather unimpressive.","TWN":"話說得很滿，結果也不過如此。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"크윽……!","JPN":"くっ……！","ENG":"Kgh...!","TWN":"唔……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"시끄러워! 내가 물러설 것 같아!?","JPN":"黙れ！　これくらいで、引き下がったりするものか！","ENG":"Shut up! Do you really think I would back down?!","TWN":"閉嘴！你以為我會退縮嗎！？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"호오, 숨겨둔 비책이 있었나?","JPN":"ほお、秘策があるとでも？","ENG":"Oh? So you had a trick up your sleeve after all.","TWN":"喔？還藏了底牌嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"도로시. 레드 슈즈가 충분히 냉각되지 않았어.","JPN":"ドロシー、レッドシューズがまだ十分冷却できていない。","ENG":"Dorothy. The Red Shoes have not cooled down enough yet.","TWN":"桃樂絲，紅鞋還沒完全冷卻。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"롱 스트라이드는 아직 테스트 중이야. 지금 가속하면 과부하가 걸릴지도 모른다고.","JPN":"ロングストライドはまだテスト段階。今加速したら過負荷になるかもしれないよ。","ENG":"Long Strides is still in testing. If you accelerate now, it could overload.","TWN":"長距離衝刺還在測試階段，現在再加速可能會超出負荷。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"그럼, 리온이 저대로 끌려가도록 내버려 두라고?","JPN":"じゃあ、あいつがリオンを連れていくのを黙って見てろっていうのか？","ENG":"Then what, you want me to just let Liona be dragged away like that?","TWN":"那你要我眼睜睜看著萊恩被帶走嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"하아, 그럴 리가 없잖아.","JPN":"はあ、そんなわけないでしょ。","ENG":"*Sigh* Of course not.","TWN":"哈，怎麼可能。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"네 구두가 식을 때까지, 내가 시간을 벌어줄게.","JPN":"ドロシーの靴が冷めるまで、ワタシが時間を稼ぐよ。","ENG":"I will buy you time until your shoes cool down.","TWN":"在你鞋子冷卻前，我來爭取時間。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"뭐라고? 설마……?","JPN":"え？　まさか……？","ENG":"What? Don't tell me...","TWN":"什麼？難道你……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"때마침 도착한 모양이네.","JPN":"ちょうど着いたようだね。","ENG":"Looks like she arrived right on time.","TWN":"看來剛好趕上了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPARROW_SL_NULL_NULL","text":{"KOREA":"반갑습니다. 닉 초퍼.","JPN":"はじめまして。ニック・チョッパー。","ENG":"Greetings. Nic. Chopper here.","TWN":"久仰了，尼克．喬巴。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"SPARROW_SL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPARROW_SL_NULL_NULL","text":{"KOREA":"친목질을 통한, 구조 요청 접수. 어떤 종류의 도움이 필요하십니까?","JPN":"コミュニケーションを通じた救助要請を確認。どのような支援をお求めですか？","ENG":"Emergency assistance request received via community channels. What kind of support do you require?","TWN":"我透過通訊收到救援請求，請問需要哪種類型的支援？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":null,"R":{"char_id":"SPARROW_SL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"훗, 재미있군.","JPN":"ふっ、面白い。","ENG":"Heh. Interesting.","TWN":"呵，真有意思。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이 도시의 방위 시스템을 해킹한 건가?","JPN":"この都市の防衛システムをハッキングしたのか？","ENG":"Did you hack this city's defense system?","TWN":"你駭入這座城市的防衛系統嗎？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"해킹이 아니야. 친목질이라고.","JPN":"ハッキングじゃない。コミュニケーションだよ。","ENG":"It is not hacking. It is asking the community.","TWN":"不是駭入，是交流。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"이 도시를 방위하고 있는 대인 전투 드론 2000대에 구조 요청을 걸었어.","JPN":"この都市を防衛している対人戦闘ドローン2000台に救助要請を送った。","ENG":"I sent a distress request to the two thousand anti-personnel combat drones defending this city.","TWN":"我已經向負責防衛城市的2000架對人作戰無人機發出求救訊號。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"아무리 카운터라도, 분당 1000발의 집중포화는 좀 아플걸?","JPN":"いくらカウンターでも、1分に1000発の集中砲撃を受けるのはきついと思うよ？","ENG":"Even for a Counter, a concentrated barrage of a thousand rounds per minute is going to hurt.","TWN":"就算是制裁者，被每分鐘1000發的集中火力掃射，也會很痛吧？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"큭, 제정신이 아니로군!","JPN":"くっ、正気の沙汰ではない！","ENG":"Kgh! You are out of your mind!","TWN":"呃，你瘋了嗎！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"설마, 네 벗까지 함께 쏴 버리겠다는 건가!","JPN":"まさか、貴様の友が撃たれても構わないということか！","ENG":"You would even shoot your own friend?","TWN":"難道你打算連自己的同伴也一起射穿！？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"어차피 카운터 상대로 이 정도는 택도 없잖아?","JPN":"どうせカウンター相手にこの程度はなんともないでしょ？","ENG":"Against a Counter, this much is nothing anyway.","TWN":"反正對制裁者來說，這點火力根本不算什麼吧？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"그보다 아저씨가 온 몸을 바쳐, 리온을 감싸는 걸 보니, 역시 계산대로네.","JPN":"それより、おじさんが体を張ってリオンを庇うところを見ると、どうやら計算通りだったみたいね。","ENG":"But more importantly, seeing you shield Liona with your own body, it is just as I expected.","TWN":"而且，看你全身護著萊恩的樣子，果然一切都在計算之中。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L1_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"뭐라고……?","JPN":"なんだと……？","ENG":"What did you say..?","TWN":"你說什麼……？"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"PUPPET_OZ_NULL_NULL","text":{"KOREA":"바로 지금이야, 도로시!","JPN":"今だよ、ドロシー！","ENG":"Now, Dorothy.","TWN":"就是現在，桃樂絲！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"PUPPET_OZ_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"이 개자식! 리온을 돌려줘……!","JPN":"このクソ野郎！　リオンを返せ……！","ENG":"You bastard! Give Liona back...!","TWN":"你這混帳！把萊恩還來……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"RUNNER_OZ_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"……확실히.","JPN":"……確かに。","ENG":"...Impressive.","TWN":"……確實。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"빠른 발을 숨겨두고 있었군. 하마터면 당할 뻔했어.","JPN":"速い脚を隠していたか。危うくやられるところだったな。","ENG":"You were hiding those fast legs. You almost had me.","TWN":"原來還藏著這麼快的腳力，差點就上當了。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"RUNNER_OZ_NULL_NULL","text":{"KOREA":"크윽, 으으윽……!","JPN":"くっ、ううっ……！","ENG":"Ghk, ugh...!","TWN":"呃……啊啊……！"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 가진 <color=#ffd34c>금서</color>의 능력이다.","JPN":"私の持つ<color=#ffd34c>禁書</color>の能力だ。","ENG":"This is the power of the <color=#ffd34c>forbidden book</color> I possess.","TWN":"這是我持有的<color=#ffd34c>禁書</color>能力。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"생명체 생체전류를 조작. 신경계를 강화하거나 마비시킬 수 있지.","JPN":"生命体の生体電流を操作し、神経系を強化、または麻痺させることができる。","ENG":"It manipulates the bioelectric currents of living beings, strengthening or paralyzing the nervous system.","TWN":"操縱生命體的生體電流，可強化或麻痺神經系統。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"한동안은 그렇게 땅을 기어라.","JPN":"しばらくはそうして地べたを這っているといい。","ENG":"Crawl on the ground like that for a while.","TWN":"你就暫時趴在地上爬吧。"},"stage":{"bg":"CITY_STREET_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};